const t="product-detail.html";function n(t=window.location.pathname){const n=t.split("?")[0].split("#")[0];return(n.endsWith("/")?n:n.substring(0,n.lastIndexOf("/")+1))||"/"}export function isStandaloneDetailPage(n=window.location.pathname){return n.endsWith(`/${t}`)||n.endsWith(t)}export function getProductDetailUrl(o,e=window.location.origin,i=window.location.pathname){return`${e}${n(i)}${t}?id=${encodeURIComponent(o)}`}export function getShortShareUrl(t,n=window.location.origin){return`${n}/p/${encodeURIComponent(t)}`}export function getLegacyDetailUrl(t){return`${n()}index.html?p=${encodeURIComponent(t)}`}export function getProductIdFromSearch(t=window.location.search,n=window.location.pathname){const o=new URLSearchParams(t),e=o.get("id")||o.get("p");if(e)return e;if(n.startsWith("/p/"))try{return decodeURIComponent(n.split("/p/")[1].split("/")[0])}catch(t){return n.split("/p/")[1].split("/")[0]}return null}